(()=>{const t="githubRepos";function e(t){const e=document.getElementById("repoTableBody");e.innerHTML="",t.forEach((t,n)=>{const o=n,r=`\n            <tr>\n                <td style="font-weight: bold;">${t.name}</td>\n                <td><a href="${t.html_url}">link</a></td>\n                <td>${t.language?t.language:"N/A"}</td>\n                <td id="lastCommit_${o}">${t.lastCommitDate}</td>\n                <td id="commitsSince_${o}">${t.totalCommits}</td>\n                <td>${t.description?t.description:"No description"}</td>\n                <td class="readme" id="readme_${o}"><div>${t.readmeHtml}</div></td>\n            </tr>\n        `;e.innerHTML+=r})}document.addEventListener("DOMContentLoaded",async()=>{const n=JSON.parse(localStorage.getItem(t)),o=localStorage.getItem(`${t}_timestamp`);if(n&&o&&Date.now()-o<432e6)console.log("Using cached data"),e(n);else try{const n=await async function(){try{const t=await fetch("/.netlify/functions/fetchRepos");if(!t.ok)throw new Error(`HTTP error! status: ${t.status}`);return t.json()}catch(t){throw console.error("Error fetching repositories:",t),t}}();localStorage.setItem(t,JSON.stringify(n)),localStorage.setItem(`${t}_timestamp`,Date.now()),e(n)}catch(t){document.getElementById("repos").innerHTML=`<p>Error fetching repositories: ${t.message}</p>`}})})();